Sure! Let’s outline the steps for your task management app first and then I’ll provide code examples for each part. 

Steps:
1. **Setup the Express.js application**: Install necessary packages and configure middleware.
2. **Design the database schema**: Create a SQLite database and define tables for users and tasks.
3. **Implement JWT authentication**: Allow users to register, log in, and secure routes with middleware.
4. **Create routes for managing tasks**: Add CRUD endpoints for tasks.

Let’s start with step 1: setting up the Express.js application.

```javascript
// index.js
const express = require('express');
const bodyParser = require('body-parser');
const jwt = require('jsonwebtoken');
const sqlite3 = require('sqlite3').verbose();
const bcrypt = require('bcrypt');

const app = express();
const PORT = 3000;
const SECRET_KEY = 'your_jwt_secret_key';

// Middleware
app.use(bodyParser.json());

// SQLite database setup
const db = new sqlite3.Database('./tasks.db', (err) => {
  if (err) {
    console.error('Error opening database:', err);
  } else {
    db.run(`CREATE TABLE IF NOT EXISTS users (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      username TEXT NOT NULL UNIQUE,
      password TEXT NOT NULL
    )`);

    db.run(`CREATE TABLE IF NOT EXISTS tasks (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      userId INTEGER NOT NULL,
      title TEXT NOT NULL,
      description TEXT,
      completed INTEGER DEFAULT 0,
      FOREIGN KEY(userId) REFERENCES users(id)
    )`);
  }
});

// Start server
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

Now that we’ve set up the application, let’s move to step 2: implementing user registration and authentication using JWT.

Great question! Here’s how you can implement user registration and login, along with JWT authentication middleware to secure your routes.

### User Registration
First, add a route to register new users. Hash their passwords using `bcrypt` before storing them in the database.

```javascript
const bcrypt = require('bcrypt');

// User registration route
app.post('/register', async (req, res) => {
  const { username, password } = req.body;
  const hashedPassword = await bcrypt.hash(password, 10);

  db.run(`INSERT INTO users (username, password) VALUES (?, ?)`, [username, hashedPassword], (err) => {
    if (err) {
      return res.status(400).json({ error: 'Username already exists' });
    }
    res.status(201).json({ message: 'User registered successfully' });
  });
});
```

### User Login
When a user logs in, validate their password and issue a signed JWT token.

```javascript
// User login route
app.post('/login', (req, res) => {
  const { username, password } = req.body;

  db.get(`SELECT * FROM users WHERE username = ?`, [username], async (err, user) => {
    if (err || !user) {
      return res.status(401).json({ error: 'Invalid username or password' });
    }

    const isPasswordValid = await bcrypt.compare(password, user.password);
    if (!isPasswordValid) {
      return res.status(401).json({ error: 'Invalid username or password' });
    }

    const token = jwt.sign({ userId: user.id }, SECRET_KEY, { expiresIn: '1h' });
    res.json({ token });
  });
});
```

### JWT Authentication Middleware
This middleware checks for a valid token on protected routes.

```javascript
// JWT authentication middleware
const authenticateJWT = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Access denied' });
  }

  jwt.verify(token, SECRET_KEY, (err, payload) => {
    if (err) {
      return res.status(403).json({ error: 'Invalid token' });
    }

    req.userId = payload.userId;
    next();
  });
};
```

### Protect Routes
You can use the `authenticateJWT` middleware to secure any route. For example:

```javascript
app.get('/tasks', authenticateJWT, (req, res) => {
  db.all(`SELECT * FROM tasks WHERE userId = ?`, [req.userId], (err, tasks) => {
    if (err) {
      return res.status(500).json({ error: 'Failed to retrieve tasks' });
    }
    res.json(tasks);
  });
});
```

This should get you started with user registration, login, and authentication. Let me know if you need help with task management or additional features!

Absolutely! Let’s implement the routes for creating, updating, and deleting tasks. These routes will use the `authenticateJWT` middleware to ensure only authenticated users have access.

### Create a New Task
Allow users to add new tasks.

```javascript
app.post('/tasks', authenticateJWT, (req, res) => {
  const { title, description } = req.body;
  const userId = req.userId;

  db.run(
    `INSERT INTO tasks (userId, title, description) VALUES (?, ?, ?)`,
    [userId, title, description],
    function (err) {
      if (err) {
        return res.status(500).json({ error: 'Failed to create task' });
      }
      res.status(201).json({ id: this.lastID, message: 'Task created successfully' });
    }
  );
});
```

### Update an Existing Task
Update a task’s title, description, or completion status.

```javascript
app.put('/tasks/:id', authenticateJWT, (req, res) => {
  const { title, description, completed } = req.body;
  const taskId = req.params.id;
  const userId = req.userId;

  db.run(
    `UPDATE tasks SET title = ?, description = ?, completed = ? WHERE id = ? AND userId = ?`,
    [title, description, completed, taskId, userId],
    function (err) {
      if (err) {
        return res.status(500).json({ error: 'Failed to update task' });
      }
      if (this.changes === 0) {
        return res.status(404).json({ error: 'Task not found' });
      }
      res.json({ message: 'Task updated successfully' });
    }
  );
});
```

### Delete a Task
Remove a task from the database.

```javascript
app.delete('/tasks/:id', authenticateJWT, (req, res) => {
  const taskId = req.params.id;
  const userId = req.userId;

  db.run(
    `DELETE FROM tasks WHERE id = ? AND userId = ?`,
    [taskId, userId],
    function (err) {
      if (err) {
        return res.status(500).json({ error: 'Failed to delete task' });
      }
      if (this.changes === 0) {
        return res.status(404).json({ error: 'Task not found' });
      }
      res.json({ message: 'Task deleted successfully' });
    }
  );
});
```

With these routes, users can add, update, and delete tasks securely. Let me know if you need help testing these or adding more functionality!

